func (o *ImportBatch) Preload(name string, retrieved any) error {
	if o == nil {
		return nil
	}

	switch name {
	case "EventProcessingAudits":
		rels, ok := retrieved.(EventProcessingAuditSlice)
		if !ok {
			return fmt.Errorf("importBatch cannot load %T as %q", retrieved, name)
		}

		o.R.EventProcessingAudits = rels

		for _, rel := range rels {
			if rel != nil {
				rel.R.ImportBatch = o
			}
		}
		return nil
	case "RaceGrid":
		rel, ok := retrieved.(*RaceGrid)
		if !ok {
			return fmt.Errorf("importBatch cannot load %T as %q", retrieved, name)
		}

		o.R.RaceGrid = rel

		if rel != nil {
			rel.R.ImportBatches = ImportBatchSlice{o}
		}
		return nil
	default:
		return fmt.Errorf("importBatch has no relationship %q", name)
	}
}

