// LoadEventProcessingAudits loads the importBatch's EventProcessingAudits into the .R struct
func (o *ImportBatch) LoadEventProcessingAudits(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if o == nil {
		return nil
	}

	// Reset the relationship
	o.R.EventProcessingAudits = nil

	related, err := o.EventProcessingAudits(mods...).All(ctx, exec)
	if err != nil {
		return err
	}

	for _, rel := range related {
		rel.R.ImportBatch = o
	}

	o.R.EventProcessingAudits = related
	return nil
}

// LoadEventProcessingAudits loads the importBatch's EventProcessingAudits into the .R struct
func (os ImportBatchSlice) LoadEventProcessingAudits(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if len(os) == 0 {
		return nil
	}

	eventProcessingAudits, err := os.EventProcessingAudits(mods...).All(ctx, exec)
	if err != nil {
		return err
	}

	for _, o := range os {
		if o == nil {
			continue
		}

		o.R.EventProcessingAudits = nil
	}

	for _, o := range os {
		if o == nil {
			continue
		}

		for _, rel := range eventProcessingAudits {

			if !rel.ImportBatchID.IsValue() {
				continue
			}
			if !(rel.ImportBatchID.IsValue() && o.ID == rel.ImportBatchID.MustGet()) {
				continue
			}

			rel.R.ImportBatch = o

			o.R.EventProcessingAudits = append(o.R.EventProcessingAudits, rel)
		}
	}

	return nil
}

